#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2e6+5;
struct node{LL l,r,h,val;}a[N];
LL n,cnt,tmp[N],sum[N],tag[N],Ans;
unordered_map<LL,LL> Ls;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp(node d1,node d2){
    return (d1.h<d2.h)||(d1.h==d2.h&&d1.val>d2.val);
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u,int l,int r){
    if(tag[u])sum[u]=tmp[r+1]-tmp[l];
    else sum[u]=sum[ls(u)]+sum[rs(u)];return;
}
void change(int u,int l,int r,int L,int R,LL k){
    if(r<L||R<=l)return;
    if(L<=l&&r<R){tag[u]+=k,push_up(u,l,r);return;}
    int mid=(l+r)>>1;
    change(ls(u),l,mid,L,R,k);
    change(rs(u),mid+1,r,L,R,k);
    push_up(u,l,r);return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++){
        int X1=read(),Y1=read();
        int X2=read(),Y2=read();
        tmp[++cnt]=X1,tmp[++cnt]=X2;
        a[i]={X1,X2,Y1,1};
        a[i+n]={X1,X2,Y2,-1};
    }sort(tmp+1,tmp+cnt+1);
    cnt=unique(tmp+1,tmp+cnt+1)-tmp-1;
    for(int i=1;i<=cnt;i++)Ls[tmp[i]]=i;
    sort(a+1,a+2*n+1,cmp);
    for(int i=1;i<2*n;i++){
        LL l=Ls[a[i].l],r=Ls[a[i].r];
        change(1,1,cnt-1,l,r,a[i].val);
        Ans+=sum[1]*(a[i+1].h-a[i].h);
    }cout<<Ans<<"\n";
    return 0;
}
